const api = require('../../utils/api.js');
const util = require('../../utils/util.js');
const constant = require('../../utils/const.js');

Page({
  data: {
    user: null,
    USER_AVATAR_URL: constant.USER_AVATAR_URL,
    avatarFile: [],
    NICKNAME_UPDATE_URL: '/pages/user/update-nickname/update-nickname?nickname=',
    GENDER_UPDATE_URL: '/pages/user/update-gender/update-gender?gender=',
    AGE_UPDATE_URL: '/pages/user/update-age/update-age?age=',
    ZODIAC_UPDATE_URL: '/pages/user/update-zodiac/update-zodiac?zodiac=',
    PROVINCE_UPDATE_URL: '/pages/user/update-province/update-province?province=',
    EMAIL_UPDATE_URL: '/pages/user/update-email/update-email?email=',
    INFO_UPDATE_URL: '/pages/user/update-info/update-info?info='
  },

  avatarSrc(avatar) {
    if (!avatar) return '';
    const token = wx.getStorageSync('token') || '';
    const tokenQuery = token ? ('?token=' + encodeURIComponent(token)) : '';
    return this.data.USER_AVATAR_URL + encodeURIComponent(avatar) + tokenQuery;
  },

  getInfo() {
    const that = this;
    const u = wx.getStorageSync('user');
    if (!u || !u.id) {
      that.setData({loading: false});
      return;
    }
    that.setData({loading: true});
    const url = '/select/' + u.id;
    api.get('user', url).then(res => {
      res.avatarUrl = this.avatarSrc(res.avatar);
      that.setData({user: res, loading: false});
    }).catch(err => {
      console.log(err);
      const cachedUser = wx.getStorageSync('user');
      if (cachedUser && cachedUser.avatar) {
        cachedUser.avatarUrl = this.avatarSrc(cachedUser.avatar);
      }
      that.setData({user: cachedUser || null, loading: false});
    });
  },

  uploadAvatar(ev) {
    const {file} = ev.detail;
    if (file.type !== 'image') {
      util.error('图片格式有误');
      return false;
    }
    if (file.size > 500 * 1024) {
      util.error('图片过大');
      return false;
    }
    const user = wx.getStorageSync('user');
    wx.uploadFile({
      url: constant.UPLOAD_AVATAR_URL + user.id,
      filePath: file.url,
      name: 'avatarFile',
      header: {
        'Content-Type': 'multipart/form-data',
        token: wx.getStorageSync('token')
      },
      success: () => {
        util.success('上传成功');
        this.getInfo();
        util.tab('/pages/user/user');
      },
      fail: err => console.log(err)
    });
  },

  logout() {
    util.confirm('即将退出登录，确认吗？', () => {
      wx.removeStorageSync('token');
      wx.removeStorageSync('user');
      util.page('/pages/index/login-by-account/login-by-account', false);
    });
  },

  onLoad() {
    if (typeof this.getTabBar === 'function' && this.getTabBar()) {
      this.getTabBar().setData({activeTab: 3});
    }
    if (util.isLogin()) {
      const cachedUser = wx.getStorageSync('user');
      if (cachedUser && cachedUser.avatar) {
        cachedUser.avatarUrl = this.avatarSrc(cachedUser.avatar);
      }
      this.setData({user: cachedUser || null});
      this.getInfo();
    } else {
      this.setData({loading: false});
    }
  },

  onShow() {
    if (wx.getStorageSync('token')) {
      const cachedUser = wx.getStorageSync('user');
      if (cachedUser && cachedUser.avatar) {
        cachedUser.avatarUrl = this.avatarSrc(cachedUser.avatar);
      }
      this.getInfo();
    }
  }
});

const api = require('../../utils/api.js');
const util = require('../../utils/util.js');
const constant = require('../../utils/const.js');

Page({
  data: {
    user: null,
    loading: true,
    MINIO_AVATAR: constant.MINIO_AVATAR,
    avatarFile: [],
    NICKNAME_UPDATE_URL: '/pages/user/update-nickname/update-nickname?nickname=',
    GENDER_UPDATE_URL: '/pages/user/update-gender/update-gender?gender=',
    AGE_UPDATE_URL: '/pages/user/update-age/update-age?age=',
    ZODIAC_UPDATE_URL: '/pages/user/update-zodiac/update-zodiac?zodiac=',
    PROVINCE_UPDATE_URL: '/pages/user/update-province/update-province?province=',
    EMAIL_UPDATE_URL: '/pages/user/update-email/update-email?email=',
    INFO_UPDATE_URL: '/pages/user/update-info/update-info?info='
  },

  normalizeUser(rawUser) {
    if (!rawUser) {
      return null;
    }
    const user = {...rawUser};
    if (user.avatarUrl) {
      return user;
    }
    if (user.avatar && /^https?:\/\//i.test(user.avatar)) {
      user.avatarUrl = user.avatar;
      return user;
    }
    const cleanAvatar = user.avatar
      ? String(user.avatar).replace(/^\/+/, '').replace(/^avatar\//i, '')
      : '';
    if (cleanAvatar) {
      const legacyAvatarBase = String(constant.MINIO_AVATAR).replace('/my-lesson/', '/mylesson/');
      user.avatarFileName = cleanAvatar;
      user.avatarUrl = `${constant.MINIO_AVATAR}${cleanAvatar}`;
      user.avatarLegacyUrl = `${legacyAvatarBase}${cleanAvatar}`;
      user.avatarProxyUrl = `${constant.USER_AVATAR_URL}${encodeURIComponent(cleanAvatar)}`;
    } else {
      user.avatarUrl = '';
    }
    return user;
  },

  handleAvatarError() {
    const user = this.data.user;
    if (!user || !user.avatarFileName) {
      return;
    }
    const current = user.avatarUrl || '';
    let next = '';
    if (current === user.avatarUrl && user.avatarLegacyUrl) {
      next = user.avatarLegacyUrl;
    } else if (current === user.avatarLegacyUrl && user.avatarProxyUrl) {
      next = user.avatarProxyUrl;
    }
    if (!next || next === current) {
      return;
    }
    this.setData({user: {...user, avatarUrl: next}});
  },

  applyUser(rawUser) {
    const user = this.normalizeUser(rawUser);
    this.setData({user});
  },

  getInfo() {
    const that = this;
    const u = wx.getStorageSync('user');
    if (!u || !u.id) {
      that.setData({loading: false});
      return;
    }
    that.setData({loading: true});
    const url = '/select/' + u.id;
    api.get('user', url).then(res => {
      that.applyUser(res);
      that.setData({loading: false});
    }).catch(err => {
      console.log(err);
      const cachedUser = wx.getStorageSync('user');
      that.applyUser(cachedUser || null);
      that.setData({loading: false});
    });
  },

  uploadAvatar(ev) {
    const {file} = ev.detail;
    if (file.type !== 'image') {
      util.error('图片格式有误');
      return false;
    }
    if (file.size > 500 * 1024) {
      util.error('图片过大');
      return false;
    }
    const user = wx.getStorageSync('user');
    wx.uploadFile({
      url: constant.UPLOAD_AVATAR_URL + user.id,
      filePath: file.url,
      name: 'avatarFile',
      header: {
        'Content-Type': 'multipart/form-data',
        token: wx.getStorageSync('token')
      },
      success: () => {
        util.success('上传成功');
        this.getInfo();
        util.tab('/pages/user/user');
      },
      fail: err => console.log(err)
    });
  },

  logout() {
    util.confirm('即将退出登录，确认吗？', () => {
      wx.removeStorageSync('token');
      wx.removeStorageSync('user');
      util.page('/pages/index/login-by-account/login-by-account', false);
    });
  },

  onLoad() {
    if (typeof this.getTabBar === 'function' && this.getTabBar()) {
      this.getTabBar().setData({activeTab: 3});
    }
    if (util.isLogin()) {
      const cachedUser = wx.getStorageSync('user');
      this.applyUser(cachedUser || null);
      this.getInfo();
    } else {
      this.setData({loading: false});
    }
  },

  onShow() {
    if (wx.getStorageSync('token')) {
      const cachedUser = wx.getStorageSync('user');
      this.applyUser(cachedUser || null);
      this.getInfo();
    } else {
      this.setData({loading: false, user: null});
    }
  }
});

// 环境IP地址
const HOST = 'localhost';
const LINUX_HOST = '192.168.211.132';
const GATEWAY_HOST = `http://${HOST}:24101`;
const SOCKET_SERVER = `ws://${HOST}:24106`;
const MINIO_HOST = `http://${LINUX_HOST}:9000/my-lesson`;
const USER_AVATAR_URL = GATEWAY_HOST + '/user-server/api/v1/user/avatar/';
const MINIO_AVATAR = MINIO_HOST + '/avatar/';
const MINIO_BANNER = MINIO_HOST + '/banner/';
const MINIO_COURSE_COVER = MINIO_HOST + '/course-cover/';
const MINIO_COURSE_SUMMARY = MINIO_HOST + '/course-summary/';
const MINIO_EPISODE_VIDEO = MINIO_HOST + '/episode-video/';
const MINIO_EPISODE_VIDEO_COVER = MINIO_HOST + '/episode-video-cover/';
const UPLOAD_AVATAR_URL = GATEWAY_HOST + '/user-server/api/v1/user/uploadAvatar/';

// 常用请求状态码
const STATUS = {
    SUCCESS: 1000
}

// 常用表单规则
const RULE = {
    TITLE: [{pattern: /^.{1,42}$/, message: '标题长度必须在1~42之间'}],
    AUTHOR: [{pattern: /^.{1,42}$/, message: '作者名称长度必须在1~42之间'}],
    INFO: [{pattern: /^.{1,170}$/, message: '描述长度必须在1~170之间'}],
    CONTENT: [{pattern: /^.{1,170}$/, message: '内容长度必须在1~170之间'}],
    VCODE: [{pattern: /^[0-9]{6}$/, message: '验证码必须是6位数字'}],
    MENU_URL: [{pattern: /^\/[a-zA-Z]{0,256}$/, message: '跳转地址必须以 / 开头，后续内容仅支持0~256个英文字母'}],
    MENU_ICON: [{pattern: /^[a-zA-Z]{1,256}$/, message: '图标仅支持1~256个英文字母'}],
    USERNAME: [{pattern: /^[a-zA-Z0-9]{4,20}$/, message: '账号必须由4到20个英文字母或数字组成'}],
    PASSWORD: [{pattern: /^[a-zA-Z0-9]{4,20}$/, message: '密码必须由4到20个英文字母或数字组成'}],
    REALNAME: [{pattern: /^[\u4e00-\u9fa5]{2,6}$/, message: '真实姓名必须由2到6个中文组成'}],
    NICKNAME: [{pattern: /^[\u4e00-\u9fa5|_a-zA-Z0-9]{2,10}$/, message: '昵称必须由2到10个中文、英文或数字组成'}],
    IDCARD: [{pattern: /^[1-9]\d{5}(19|20)\d{2}((0[1-9])|(1[0-2]))(([0-2][1-9])|10|20|30|31)\d{3}[0-9Xx]$/, message: '身份证号格式不正确'}],
    PHONE: [{pattern: /^1(3[0-9]|4[01456879]|5[0-35-9]|6[2567]|7[0-8]|8[0-9]|9[0-35-9])\d{8}$/, message: '手机号码格式不正确'}],
    EMAIL: [{pattern: /^[a-zA-Z0-9_-]+@[a-zA-Z0-9_-]+(\.[a-zA-Z0-9_-]+)+$/, message: '电子邮箱格式不正确'}],
    PROVINCE: [{pattern: /^[\u4e00-\u9fa5]{2,20}$/, message: '省份必须由2到20个中文组成'}],
    CODE: [{pattern: /^.{1,42}$/, message: '兑换口令长度必须在1~42之间'}],
    SN: [{pattern: /^.{1,42}$/, message: '订单编号长度必须在1~42之间'}],
}

// 项目大标题
const PROJECT_TITLE = '绝对精品课 - 我的课堂';

// 项目小标题
const PROJECT_SUB_TITLE = 'Welcome To Lesson Project';

// 省份选项
const PROVINCE_OPTIONS = [
    {
        id: 0,
        text: "华北地区",
        children: [{text: "北京市", id: "北京市"}, {text: "天津市", id: "天津市"}, {text: "河北省", id: "河北省"}, {text: "山西省", id: "山西省"}, {text: "内蒙古自治区", id: "内蒙古自治区"}]
    },
    {
